/* ROBUST VERSION v1.2.1 - handles all Telegram input paths */
const input = $input.first()?.json;

// Path 1: Execute Workflow from NN_01 (Telegram update body under input.body)
// Path 2: Direct webhook call (body already unwrapped)
// Path 3: Direct fields (chat_id, text at root)
const bodyLayer = input?.body || input || {};

// Telegram update: {update_id, message:{chat:{id}, text, from:{first_name}}}
const message = bodyLayer.message || bodyLayer.channel_post || bodyLayer;

const chat_id = message.chat?.id || bodyLayer.chat_id || input?.chat_id;
const text = message.text || bodyLayer.text || input?.text;

if (!chat_id || !text) {
  return [{
    json: {
      success: false,
      error_code: 'VALIDATION_ERROR',
      error_message: 'Payload missing required chat_id or text fields.',
      debug_received: JSON.stringify(input).substring(0, 200),
      data: null,
      _meta: { source: 'NN_02_Message_Parser', timestamp: new Date().toISOString(), version: '1.2.1' }
    }
  }];
}

const username = message.from?.first_name || message.chat?.first_name || bodyLayer.username || 'Unknown';

// SEC_02: Sanitize
const safeText = text.replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 500);
const safeUsername = username.replace(/\\/g, '\\\\').replace(/'/g, "''").substring(0, 100);

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      chat_id: chat_id,
      text: safeText,
      username: safeUsername,
      type: 'text'
    },
    _meta: { source: 'NN_02_Message_Parser', timestamp: new Date().toISOString(), version: '1.2.1' }
  }
}];

